#include<bits/stdc++.h>
using namespace std;

long long euler_phi(long long n){
    long long ans=n;
    for(int i=2;1LL*i*i<=n;i++)
        if(n%i==0){
            ans=ans/i*(i-1);
            while(n%i==0)
                n/=i;
        }
    if(n>1)
        ans=ans/n*(n-1);
    return ans;
}

long long quick_mi(long long a,long long b,long long p){
    long long ans=1,base=a;
    while(b){
        if(b&1)
            ans=(__int128)ans*base%p;
        base=(__int128)base*base%p,b>>=1;
    }
    return ans;
}

int main(){
    long long l;
    int T=0;
    while(++T){
        scanf("%lld",&l);
        if(!l)
            break;
        l=9*l/__gcd(l,8ll);
        long long k=euler_phi(l);
        if(__gcd(10ll,l)>1){
            printf("Case %d: 0\n",T);
            continue;
        }
        long long mint=1e18;
        for(int i=1;1LL*i*i<=k;i++)
            if(k%i==0){
                if(quick_mi(10,i,l)==1)
                    mint=min(mint,1ll*i);
                if(quick_mi(10,k/i,l)==1)
                    mint=min(mint,k/i);
            }
        printf("Case %d: %lld\n",T,mint);
    }
    return 0;
}
